  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Robinhood Earn: how deposits flow</text>
    <text x="20" y="54" fill="#a1a1aa" font-size="13" font-family="sans-serif">Lend USDG → Morpho markets (Steakhouse-curated) → three collaterals</text>
    <rect x="15" y="140" width="150" height="100" rx="10" fill="#18181b" stroke="#10b981" stroke-width="1.5"/>
